import { execSync } from "child_process"; import fs from "fs"; import crypto from "crypto";
const WP_USER=process.env.WP_USER, WP_PASS=process.env.WP_APP_PASS;
const BASE="https://dev.avesa.lt";
const AUTH="Basic "+Buffer.from(`${WP_USER}:${WP_PASS}`).toString("base64");
const repo=process.env.GH_REPO, tok=process.env.GH_TOKEN;
function commit(name,str){ const url='https://api.github.com/repos/'+repo+'/contents/screenshots/'+name; let sha=''; try{ sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||''; }catch(e){} const body={message:'deploy550',branch:'main',content:Buffer.from(str,'utf8').toString('base64')}; if(sha) body.sha=sha; fs.writeFileSync('/tmp/cb.json',JSON.stringify(body)); execSync('curl -s -o /dev/null -X PUT -H "Authorization: Bearer '+tok+'" -H "Accept: application/vnd.github+json" -d @/tmp/cb.json "'+url+'"',{encoding:'utf8'}); }
function exec(cmd){ try{ return execSync(cmd,{encoding:'utf8',maxBuffer:300000000}); }catch(e){ return 'EXC:'+e.message; } }
const code=Buffer.from("",'base64').toString('utf8');
(async()=>{
  var out={};
  // 1) current scope
  var cur=exec('curl -sk -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/550"');
  var scope='global'; try{ scope=JSON.parse(cur).scope||'global'; }catch(e){}
  out.old_scope=scope;
  // 2) PUT v8 (--data-binary)
  fs.writeFileSync('/tmp/p550.json', JSON.stringify({name:'Petshop Susidėjimo Rinkinio Kūrimo Forma v8', code:code, scope:scope, active:true}));
  var put=exec('curl -sk -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/p550.json "'+BASE+'/wp-json/code-snippets/v1/snippets/550"');
  // 3) readback + md5
  var rb=exec('curl -sk -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/550"');
  try{ var j=JSON.parse(rb); out.name=j.name; out.active=j.active; out.scope=j.scope; out.code_len=(j.code||'').length; out.code_md5=crypto.createHash('md5').update(j.code||'','utf8').digest('hex'); }catch(e){ out.err='readback parse: '+e.message; out.raw=rb.slice(0,200); }
  commit('deploy550_v8.json', JSON.stringify(out));
  console.log(JSON.stringify(out));
})();
